={{ (() => {
  const H = $json.highEdge || [], N = $json.noEdge || [];
  const fmt = (m) => {
    const side = m.edge >= 0 ? 'BUY YES' : 'BUY NO';
    const ci = (m.confidence_lower != null && m.confidence_upper != null)
      ? ' (CI ' + (m.confidence_lower*100).toFixed(0) + '-' + (m.confidence_upper*100).toFixed(0) + '%)' : '';
    const link = m.event_slug ? '\nhttps://polymarket.com/event/' + m.event_slug : '';
    return '[' + (m.source||'polymarket') + '] ' + m.asset.toUpperCase() + ': ' + m.question + '\n' +
      'Now: $' + (m.current_price!=null ? Number(m.current_price).toLocaleString() : 'N/A') +
      ' | Target: $' + Number(m.target).toLocaleString() +
      ' | Horizon: ' + m.horizon_days + 'd (ends ' + (m.end_date||'N/A') + ')\n' +
      'Sim: ' + (m.sim_probability*100).toFixed(1) + '%' + ci +
      ' | Market: ' + (m.yes_price*100).toFixed(1) + '%' +
      ' | Edge: ' + m.edge.toFixed(1) + '% → ' + side + '\n' +
      'Volume: $' + (m.volume/1000).toFixed(0) + 'K' + link;
  };
  let text = '';
  if (H.length) text += '🎯 Edge Found!\n\n' + H.map(fmt).join('\n\n');
  if (N.length) text += (text ? '\n\n---\n\n' : '') + '📊 Overpriced (potential NO edge):\n\n' + N.map(fmt).join('\n\n');
  if (!text) text = 'No edge or overpriced markets this run.';
  return JSON.stringify({ chat_id: $env.TELEGRAM_TRADING_CHAT_ID, text });
})() }}

